CustomField.formula:
if(leaseworks__Field_Type__c == "reference", HYPERLINK('/' & leaseworks__Y_Hidden_Old_Record_Id__c, leaseworks__Y_Hidden_Old_Value__c,'_blank'),
if(leaseworks__Field_Type__c == "url", HYPERLINK(leaseworks__Y_Hidden_Old_Value__c, "Click Here",'_blank'),
if(leaseworks__Field_Type__c == "email", HYPERLINK('mailto:' & leaseworks__Y_Hidden_Old_Value__c, leaseworks__Y_Hidden_Old_Value__c,'_blank'),
if(leaseworks__Field_Type__c == "phone", HYPERLINK('tel:' & leaseworks__Y_Hidden_Old_Value__c, leaseworks__Y_Hidden_Old_Value__c,'_blank'),
if(leaseworks__Field_Type__c == "date", TEXT(DATEVALUE(LEFT(leaseworks__Y_Hidden_Old_Value__c, 10))),
if(leaseworks__Field_Type__c == "datetime", TEXT(DATETIMEVALUE(leaseworks__Y_Hidden_Old_Value__c)),
if(leaseworks__Field_Type__c == "currency",
	IF(ISNULL(leaseworks__Y_Hidden_Old_Value__c ), '', '$' + 
		IF(VALUE(leaseworks__Y_Hidden_Old_Value__c) >= 1000000, 
			TEXT(FLOOR(VALUE(leaseworks__Y_Hidden_Old_Value__c) / 1000000)) & ",", ""
		) 
		& 
		IF(VALUE(leaseworks__Y_Hidden_Old_Value__c) >= 1000, 
			RIGHT(TEXT(FLOOR(VALUE(leaseworks__Y_Hidden_Old_Value__c) / 1000)), 3) & ",", ""
		) 
		& 
			RIGHT(TEXT(FLOOR(VALUE(leaseworks__Y_Hidden_Old_Value__c) )), 3) & "." 
		& 
		IF(MOD(VALUE(leaseworks__Y_Hidden_Old_Value__c) , 1) * 100 < 10, "0" & 
			TEXT(ROUND(MOD(VALUE(leaseworks__Y_Hidden_Old_Value__c) , 1), 2) * 100), 
			TEXT(MIN(ROUND(MOD(VALUE(leaseworks__Y_Hidden_Old_Value__c) , 1), 2) * 100, 99)) 
		)
	),
	leaseworks__Y_Hidden_Old_Value__c
)))))))
